import { MOCK_HERBS } from './mockData';

// 定义后端 API 地址
const API_BASE_URL = 'http://localhost:3001/api';

/**
 * 这是一个 API 代理服务。
 * 它会尝试连接 Node.js 后端。如果连接失败（例如在无后端的预览环境中），
 * 它会自动回退到使用前端 Mock 数据。
 */

async function fetchWithFallback(endpoint: string, options?: RequestInit, fallbackData?: any) {
  try {
    // 尝试请求真实后端，设置 1.5秒超时
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 1500);

    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      signal: controller.signal
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || `API Error: ${response.status}`);
    }
    return await response.json();
  } catch (error: any) {
    if (error.name === 'AbortError' || error.message.includes('Failed to fetch') || error.message.includes('NetworkError')) {
       console.warn(`无法连接到后端 (${API_BASE_URL}${endpoint})，使用本地模拟数据。`, error);
       if (fallbackData !== undefined) return fallbackData;
    }
    throw error;
  }
}

export const api = {
  // 登录
  login: async (username: string, password?: string): Promise<User> => {
    return fetchWithFallback('/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username, password })
    }, {
      // MOCK 数据回退
      id: 'mock-user-id',
      username,
      avatar: 'default.png',
      role: username === 'admin' ? 'admin' : 'user'
    });
  },

  // 搜索草药
  searchHerbs: async (query: string): Promise<Herb[]> => {
    const mockResult = query 
      ? MOCK_HERBS.filter(h => h.name.includes(query) || h.pinyin.toLowerCase().includes(query.toLowerCase()))
      : MOCK_HERBS;

    return fetchWithFallback(`/herbs?q=${encodeURIComponent(query)}`, {
      method: 'GET'
    }, mockResult);
  },

  // 保存体质检测结果
  saveTestResult: async (username: string, result: ConstitutionType): Promise<any> => {
    return fetchWithFallback('/test-result', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username, result })
    }, { success: true, mock: true });
  },

  // 获取所有用户 (Admin Only)
  getUsers: async (): Promise<User[]> => {
    return fetchWithFallback('/users', {
      method: 'GET'
    }, [
      // Mock Users List
      { id: '1', username: 'admin', avatar: 'default.png', role: 'admin' },
      { id: '2', username: 'student_zhang', avatar: 'default.png', role: 'user' },
      { id: '3', username: 'doctor_li', avatar: 'default.png', role: 'user' },
    ]);
  },

  // 删除用户 (Admin Only)
  deleteUser: async (id: string): Promise<any> => {
    return fetchWithFallback(`/users/${id}`, {
      method: 'DELETE'
    }, { success: true });
  }
};

