const express = require('express');
const cors = require('cors');
const { GoogleGenAI } = require('@google/genai');
const crypto = require('crypto'); // 引入加密模块
const HERBS_DATA = require('./data'); // 导入中药数据
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 3001;

// --- 中间件 ---
app.use(cors()); // 允许跨域请求
app.use(express.json()); // 解析 JSON 请求体

// --- 内存数据库 ---
// 注意：在实际生产中，这些应该存储在 MongoDB 或 MySQL
// 初始化一个默认管理员以便演示
let usersDB = []; 
// 检测记录表 { id, username, result, date }
let testsDB = []; 

// --- 辅助函数：密码加密 ---
function hashPassword(password) {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.scryptSync(password, salt, 64).toString('hex');
  return { salt, hash };
}

function verifyPassword(password, salt, hash) {
  const verifyHash = crypto.scryptSync(password, salt, 64).toString('hex');
  return hash === verifyHash;
}

// --- API 路由 ---

// 0. 根路由 (健康检查)
app.get('/', (req, res) => {
  res.send('<h1>✅ 本草智库后端服务正在运行</h1><p>BenCao AI Backend Server is Running.</p>');
});

/**
 * 1. 用户登录/注册接口
 */
app.post('/api/login', (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.status(400).json({ error: "用户名和密码不能为空" });
  }

  const user = usersDB.find(u => u.username === username);

  if (user) {
    // 登录
    if (verifyPassword(password, user.salt, user.passwordHash)) {
      console.log(`用户登录成功: ${username} (${user.role})`);
      res.json({
        id: user.id,
        username: user.username,
        avatar: user.avatar,
        role: user.role
      });
    } else {
      res.status(401).json({ error: "密码错误" });
    }
  } else {
    // 注册
    console.log(`新用户注册: ${username}`);
    const { salt, hash } = hashPassword(password);

    // 简单的权限逻辑：如果用户名是 'admin'，则给予管理员权限
    const role = username === 'admin' ? 'admin' : 'user';

    const newUser = {
      id: Date.now().toString(),
      username,
      salt,
      passwordHash: hash,
      avatar: 'default.png',
      role: role
    };
    usersDB.push(newUser);

    res.json({
      id: newUser.id,
      username: newUser.username,
      avatar: newUser.avatar,
      role: newUser.role,
      message: "注册成功并自动登录"
    });
  }
});

/**
 * 2. 获取草药列表 (支持搜索)
 */
app.get('/api/herbs', (req, res) => {
  const { q } = req.query;
  if (!q) return res.json(HERBS_DATA);

  const searchTerm = q.toLowerCase();
  const filtered = HERBS_DATA.filter(herb => 
    herb.name.includes(searchTerm) || 
    herb.pinyin.toLowerCase().includes(searchTerm) ||
    herb.efficacy.includes(searchTerm)
  );

  res.json(filtered);
});

/**
 * 3. 体质检测结果 (保存 & 获取)
 */
app.post('/api/test-result', (req, res) => {
  const { username, result } = req.body;

  if (!username || !result) {
    return res.status(400).json({ error: "缺少必要参数" });
  }

  const newTest = {
    id: Date.now().toString(),
    username,
    result,
    date: new Date().toISOString()
  };

  testsDB.push(newTest);
  console.log(`保存检测结果: ${username} -> ${result}`);

  res.json({ success: true, data: newTest });
});

app.get('/api/test-result', (req, res) => {
  const { username } = req.query;
  if (!username) return res.status(400).json({ error: "缺少 username 参数" });

  // 获取该用户最近的一次记录
  const userTests = testsDB.filter(t => t.username === username);
  const lastTest = userTests.length > 0 ? userTests[userTests.length - 1] : null;

  res.json(lastTest || { result: null });
});

/**
 * 4. 获取所有用户 (仅限管理员)
 */
app.get('/api/users', (req, res) => {
  const safeUsers = usersDB.map(u => ({
    id: u.id,
    username: u.username,
    avatar: u.avatar,
    role: u.role,
    registeredAt: new Date(parseInt(u.id)).toISOString().split('T')[0]
  }));
  res.json(safeUsers);
});

/**
 * 5. 删除用户 (仅限管理员)
 */
app.delete('/api/users/:id', (req, res) => {
  const { id } = req.params;
  const initialLength = usersDB.length;
  usersDB = usersDB.filter(u => u.id !== id);

  if (usersDB.length < initialLength) {
    console.log(`用户已删除 ID: ${id}`);
    res.json({ success: true });
  } else {
    res.status(404).json({ error: "用户不存在" });
  }
});

