app.post('/api/test-result', (req, res) => {
  const { username, result } = req.body;

  if (!username || !result) {
    return res.status(400).json({ error: "缺少必要参数" });
  }

  const newTest = {
    id: Date.now().toString(),
    username,
    result,
    date: new Date().toISOString()
  };

  testsDB.push(newTest);
  console.log(`保存检测结果: ${username} -> ${result}`);

  res.json({ success: true, data: newTest });
});

app.get('/api/test-result', (req, res) => {
  const { username } = req.query;
  if (!username) return res.status(400).json({ error: "缺少 username 参数" });

  // 获取该用户最近的一次记录
  const userTests = testsDB.filter(t => t.username === username);
  const lastTest = userTests.length > 0 ? userTests[userTests.length - 1] : null;

  res.json(lastTest || { result: null });
});

/**
 * 4. 获取所有用户 (仅限管理员)
 */
app.get('/api/users', (req, res) => {
  const safeUsers = usersDB.map(u => ({
    id: u.id,
    username: u.username,
    avatar: u.avatar,
    role: u.role,
    registeredAt: new Date(parseInt(u.id)).toISOString().split('T')[0]
  }));
  res.json(safeUsers);
});

/**
 * 5. 删除用户 (仅限管理员)
 */
app.delete('/api/users/:id', (req, res) => {
  const { id } = req.params;
  const initialLength = usersDB.length;
  usersDB = usersDB.filter(u => u.id !== id);

  if (usersDB.length < initialLength) {
    console.log(`用户已删除 ID: ${id}`);
    res.json({ success: true });
  } else {
    res.status(404).json({ error: "用户不存在" });
