语言风格：典雅、通俗易懂。
`;

let chatSession: Chat | null = null;

export const initChatSession = () => {
  // Use gemini-3-pro-preview for complex text tasks such as TCM health consultation
  chatSession = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.7, // Slightly creative but grounded
    },
  });
  return chatSession;
};

export const sendMessageToGemini = async (message: string): Promise<AsyncIterable<GenerateContentResponse>> => {
  if (!chatSession) {
    initChatSession();
  }

  try {
    const streamResult = await chatSession!.sendMessageStream({ message });
    return streamResult;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

const express = require('express');
