      contents: message,
      config: {
        systemInstruction: "你是一位资深的中医药专家助手。请以专业、亲切的口吻回答用户的健康咨询。",
      }
    });

    // Extract text output using .text property as per guidelines
    res.json({ text: response.text });
  } catch (error) {
    console.error("AI Error:", error);
    res.status(500).json({ error: "AI 服务暂时不可用" });
  }
});

app.listen(PORT, () => {
  console.log(`✅ 本草智库后端服务器已启动`);
  console.log(`   接口地址: http://localhost:${PORT}`);
  if (!process.env.API_KEY) {
      console.warn("⚠️  警告: 未检测到 API_KEY。请确保根目录 .env 文件已配置。");
  }
});

import React, { useState, useRef, useEffect } from 'react';
import { GenerateContentResponse } from '@google/genai';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage } from '../types';
import { LoaderIcon, SendIcon, MessageCircleIcon, UserIcon } from '../components/Icons';
import Markdown from 'react-markdown';

const Recommendation: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: '您好，我是您的智能中医助手。请告诉我您哪里不舒服，或者想咨询哪方面的养生建议？（例如：最近总是失眠多梦、口干舌燥）'
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      // Create a placeholder for the model's response
      const modelMsgId = (Date.now() + 1).toString();
      setMessages(prev => [...prev, { id: modelMsgId, role: 'model', text: '' }]);

      const stream = await sendMessageToGemini(userMsg.text);

      let fullText = '';

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        // Accessing .text as a property as required by guidelines
        if (c.text) {
          fullText += c.text;
          setMessages(prev => 
            prev.map(msg => 
              msg.id === modelMsgId ? { ...msg, text: fullText } : msg
            )
          );
        }
      }

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: '抱歉，系统暂时繁忙，请稍后再试。',
        isError: true
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="h-[calc(100vh-4rem)] flex flex-col bg-white rounded-2xl shadow-lg border border-tcm-100 overflow-hidden">
      <div className="bg-tcm-800 p-4 flex items-center justify-between shadow-md z-10">
        <div className="flex items-center gap-3">
          <div className="bg-white/10 p-2 rounded-full">
            <MessageCircleIcon className="text-white w-5 h-5" />
          </div>
          <div>
             <h2 className="text-white font-medium">中医智能问诊</h2>
             <p className="text-tcm-300 text-xs">Powered by Gemini 3 Pro</p>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-paper">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center ${
              msg.role === 'user' ? 'bg-tcm-600' : 'bg-tcm-100 border border-tcm-200'
            }`}>
              {msg.role === 'user' ? (
                <UserIcon className="text-white w-5 h-5" />
              ) : (
                <span className="text-tcm-800 font-serif font-bold">医</span>
              )}
            </div>

            <div className={`max-w-[80%] rounded-2xl px-5 py-4 shadow-sm ${
              msg.role === 'user' 
                ? 'bg-tcm-600 text-white rounded-tr-none' 
                : 'bg-white border border-tcm-100 text-tcm-900 rounded-tl-none'
            } ${msg.isError ? 'bg-red-50 text-red-600 border-red-200' : ''}`}>
               {msg.role === 'model' ? (
                 <div className="prose prose-sm prose-emerald max-w-none">
                   <Markdown>{msg.text}</Markdown>
                   {msg.text === '' && <span className="animate-pulse">...</span>}
                 </div>
               ) : (
                 <p className="whitespace-pre-wrap">{msg.text}</p>
               )}
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-tcm-100">
        <div className="relative flex items-end gap-2 max-w-4xl mx-auto">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="描述您的症状或疑问..."
            className="flex-1 bg-tcm-50 border border-tcm-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-tcm-500 outline-none resize-none min-h-[50px] max-h-[150px]"
            rows={1}
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="bg-tcm-700 hover:bg-tcm-800 disabled:bg-gray-300 disabled:cursor-not-allowed text-white p-3 rounded-xl transition-colors shadow-sm mb-0.5"
          >
            {isLoading ? <LoaderIcon className="animate-spin w-5 h-5" /> : <SendIcon className="w-5 h-5" />}
          </button>
        </div>
        <p className="text-center text-xs text-gray-400 mt-2">
          AI生成内容仅供参考，不可替代专业医疗诊断。
        </p>
      </div>
    </div>
  );
};

export default Recommendation;
